html:
{% set co = get_company_info(doc.company) %}
{% set co_addr = get_company_address(doc.company) %}

<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body {
  font-family: 'Inter', Arial, sans-serif;
  font-size: 11px;
  color: #1a1a1a;
  background: white;
  padding: 8px;
}

/* ── Header ── */
.ol-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  padding-bottom: 18px;
  border-bottom: 3px solid #0F2340;
  margin-bottom: 22px;
}
.ol-company-name {
  font-size: 20px;
  font-weight: 800;
  color: #0F2340;
  letter-spacing: 1.5px;
  text-transform: uppercase;
}
.ol-company-meta {
  font-size: 9.5px;
  color: #555;
  margin-top: 6px;
  line-height: 1.7;
}
.ol-doc-block {
  text-align: right;
  min-width: 200px;
}
.ol-doc-type {
  font-size: 16px;
  font-weight: 800;
  color: #0055FF;
  text-transform: uppercase;
  letter-spacing: 2px;
}
.ol-doc-number {
  font-size: 12px;
  font-weight: 700;
  color: #0F2340;
  margin-top: 5px;
}
.ol-doc-meta {
  font-size: 9.5px;
  color: #555;
  margin-top: 5px;
  line-height: 1.8;
}
.ol-doc-meta b { color: #0F2340; }

/* ── Client block ── */
.ol-section-label {
  font-size: 8.5px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1.2px;
  color: #0055FF;
  margin-bottom: 6px;
}
.ol-client-box {
  display: inline-block;
  background: #f6f8fd;
  border-left: 3px solid #0F2340;
  padding: 10px 14px;
  min-width: 220px;
  margin-bottom: 22px;
}
.ol-client-name {
  font-size: 12px;
  font-weight: 700;
  color: #0F2340;
}
.ol-client-addr {
  font-size: 9.5px;
  color: #555;
  margin-top: 4px;
  line-height: 1.6;
}

/* ── Items table ── */
table.ol-items {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 16px;
  font-size: 10.5px;
}
table.ol-items thead tr {
  background: #0F2340;
  color: #fff;
}
table.ol-items thead th {
  padding: 8px 10px;
  font-size: 9.5px;
  font-weight: 600;
  letter-spacing: 0.4px;
}
table.ol-items tbody tr {
  border-bottom: 1px solid #e4e8f0;
}
table.ol-items tbody tr:nth-child(even) {
  background: #f6f8fd;
}
table.ol-items tbody td {
  padding: 7px 10px;
  vertical-align: top;
}
.ol-item-desc {
  font-size: 9px;
  color: #777;
  margin-top: 2px;
}

/* ── Totals ── */
.ol-totals-wrap {
  display: flex;
  justify-content: flex-end;
  margin-bottom: 24px;
}
.ol-totals {
  width: 260px;
}
.ol-totals table {
  width: 100%;
  border-collapse: collapse;
}
.ol-totals td {
  padding: 5px 8px;
  font-size: 10.5px;
}
.ol-totals .lbl { color: #555; }
.ol-totals .val { text-align: right; font-weight: 600; }
.ol-totals .sep { border-top: 1px solid #ddd; }
.ol-total-row { background: #0F2340; color: #fff; }
.ol-total-row td { padding: 8px 10px; font-size: 12px; font-weight: 700; }
.ol-total-row .val { text-align: right; }

/* ── Terms & validity ── */
.ol-terms {
  font-size: 9.5px;
  color: #555;
  border-top: 1px solid #ddd;
  padding-top: 12px;
  margin-bottom: 10px;
  line-height: 1.6;
}
.ol-terms b { color: #0F2340; }
.ol-validity {
  font-size: 9.5px;
  color: #0055FF;
  font-style: italic;
  margin-bottom: 28px;
}

/* ── Footer ── */
.ol-footer {
  display: flex;
  justify-content: space-between;
  align-items: flex-end;
  border-top: 1px solid #ddd;
  padding-top: 14px;
  font-size: 9px;
  color: #888;
}
.ol-sig-block { text-align: center; width: 180px; }
.ol-sig-line {
  border-bottom: 1px solid #aaa;
  height: 44px;
  margin-bottom: 5px;
}

.tr { text-align: right; }
.tc { text-align: center; }
</style>

<!-- HEADER -->
<div class="ol-header">
  <div>
    <div class="ol-company-name">{{ doc.company }}</div>
    <div class="ol-company-meta">
      {%- if co_addr %}{{ co_addr }}<br>{% endif %}
      {%- if co.phone %}{{ _("Tél") }}: {{ co.phone }}<br>{% endif %}
      {%- if co.email %}{{ co.email }}<br>{% endif %}
      {%- if co.tax_id %}{{ _("ICE") }} : {{ co.tax_id }}{% endif %}
    </div>
  </div>
  <div class="ol-doc-block">
    <div class="ol-doc-type">{{ _("Devis") }}</div>
    <div class="ol-doc-number">{{ doc.name }}</div>
    <div class="ol-doc-meta">
      {{ _("Date") }} : <b>{{ frappe.format_date(doc.transaction_date) }}</b><br>
      {%- if doc.valid_till %}
      {{ _("Valide jusqu'au") }} : <b>{{ frappe.format_date(doc.valid_till) }}</b><br>
      {%- endif %}
      {%- if doc.custom_source_pricing_sheet %}
      {{ _("Grille") }} : <b>{{ doc.custom_source_pricing_sheet }}</b>
      {%- endif %}
    </div>
  </div>
</div>

<!-- CLIENT -->
<div class="ol-section-label">{{ _("Destinataire") }}</div>
<div class="ol-client-box">
  <div class="ol-client-name">{{ doc.customer_name }}</div>
  {%- if doc.address_display %}
  <div class="ol-client-addr">{{ doc.address_display | striptags | replace('\n', ', ') }}</div>
  {%- endif %}
  {%- if doc.contact_display %}
  <div class="ol-client-addr" style="margin-top:3px">{{ _("Contact") }} : {{ doc.contact_display }}</div>
  {%- endif %}
</div>

<!-- ITEMS -->
<div class="ol-section-label">{{ _("Articles") }}</div>
<table class="ol-items">
  <thead>
    <tr>
      <th class="tc" style="width:28px">#</th>
      <th style="width:110px">{{ _("Référence") }}</th>
      <th>{{ _("Désignation") }}</th>
      <th class="tc" style="width:48px">{{ _("Qté") }}</th>
      <th class="tc" style="width:38px">{{ _("U.") }}</th>
      <th class="tr" style="width:96px">{{ _("Prix Unit. HT") }}</th>
      <th class="tr" style="width:96px">{{ _("Montant HT") }}</th>
    </tr>
  </thead>
  <tbody>
    {%- for item in doc.items %}
    <tr>
      <td class="tc">{{ loop.index }}</td>
      <td>{{ item.item_code }}</td>
      <td>
        {{ item.item_name }}
        {%- if item.description and item.description != item.item_name %}
        <div class="ol-item-desc">{{ item.description | striptags }}</div>
        {%- endif %}
      </td>
      <td class="tc">{{ item.qty | int if item.qty == (item.qty | int) else item.qty }}</td>
      <td class="tc">{{ item.uom }}</td>
      <td class="tr">{{ format_currency_fr(item.rate, doc.currency) }}</td>
      <td class="tr">{{ format_currency_fr(item.amount, doc.currency) }}</td>
    </tr>
    {%- endfor %}
  </tbody>
</table>

<!-- TOTALS -->
<div class="ol-totals-wrap">
  <div class="ol-totals">
    <table>
      <tr>
        <td class="lbl">{{ _("Sous-total HT") }}</td>
        <td class="val">{{ format_currency_fr(doc.total, doc.currency) }}</td>
      </tr>
      {%- for tax in doc.taxes %}
      <tr>
        <td class="lbl">{{ tax.description }}</td>
        <td class="val">{{ format_currency_fr(tax.tax_amount, doc.currency) }}</td>
      </tr>
      {%- endfor %}
      {%- if doc.discount_amount %}
      <tr>
        <td class="lbl">{{ _("Remise") }}</td>
        <td class="val">- {{ format_currency_fr(doc.discount_amount, doc.currency) }}</td>
      </tr>
      {%- endif %}
      <tr class="sep"><td colspan="2"></td></tr>
      <tr class="ol-total-row">
        <td>{{ _("TOTAL TTC") }}</td>
        <td class="val">{{ format_currency_fr(doc.grand_total, doc.currency) }}</td>
      </tr>
    </table>
  </div>
</div>

<!-- TERMS -->
{%- if doc.terms %}
<div class="ol-terms"><b>{{ _("Conditions") }} :</b> {{ doc.terms }}</div>
{%- endif %}

<div class="ol-validity">
  {%- if doc.valid_till %}
  {{ _("Ce devis est valable jusqu'au") }} {{ frappe.format_date(doc.valid_till) }}.
  {%- else %}
  {{ _("Ce devis est valable 10 jours à compter de sa date d'émission.") }}
  {%- endif %}
</div>

<!-- FOOTER -->
<div class="ol-footer">
  <div>
    <b>{{ doc.company }}</b>
    {%- if co_addr %}<br>{{ co_addr }}{% endif %}
    {%- if co.phone %}<br>{{ co.phone }}{% endif %}
  </div>
  <div class="ol-sig-block">
    <div class="ol-sig-line"></div>
    <div>{{ _("Signature &amp; Cachet Client") }}</div>
    <div style="margin-top:5px;font-size:8px">{{ _("Bon pour accord") }}</div>
  </div>
</div>
